perDuper\");\n    subOpts.setRunner(CrashingRunner.class);\n\n    PipelineOptionsValidator.validate(SubOptions.class, subOpts);\n    PipelineOptionsValidator.validate(SuperOptions.class, subOpts);\n  }\n}\n", "numLines": 395, "startLine": 1, "totalLines": 395}}

