package org.apache.beam.sdk.options;

import static org.junit.Assert.assertEquals;
import static org.junit.Assert.assertFalse;
import static org.junit.Assert.assertTrue;

import org.junit.Test;
import org.junit.runner.RunWith;
import org.junit.runners.JUnit4;

/** Tests for {@link PipelineOptionsValidator.Builder} and {@link ValidationResult}. */
@RunWith(JUnit4.class)
public class PipelineOptionsValidatorBuilderTest {

  /** Test options interface with a string and integer property. */
  public interface TestOptions extends PipelineOptions {
    String getJobName();

    void setJobName(String jobName);

    Integer getParallelism();

    void setParallelism(Integer parallelism);
  }

  // -----------------------------------------------------------------------
  // validateRequired
  // -----------------------------------------------------------------------

  @Test
  public void testValidateRequired_presentValue_isValid() {
    TestOptions opts = PipelineOptionsFactory.as(TestOptions.class);
    opts.setJobName("my-job");

    ValidationResult result =
        PipelineOptionsValidator.builder().validateRequired("jobName").validate(opts);

    assertTrue(result.isValid());
    assertTrue(result.getErrors().isEmpty());
  }

  @Test
  public void testValidateRequired_nullValue_hasError() {
    TestOptions opts = PipelineOptionsFactory.as(TestOptions.class);
    // jobName is intentionally left unset (null)

    ValidationResult result =
        PipelineOptionsValidator.builder().validateRequired("jobName").validate(opts);

    assertFalse(result.isValid());
    assertEquals(1, result.getErrors().size());
    assertTrue(result.getErrors().get(0).contains("jobName"));
  }

  @Test
  public void testValidateRequired_unknownField_hasError() {
    TestOptions opts = PipelineOptionsFactory.as(TestOptions.class);

    ValidationResult result =
        PipelineOptionsValidator.builder().validateRequired("nonExistentField").validate(opts);

    // A field that doesn't exist returns null, so it is treated as missing.
    assertFalse(result.isValid());
  }

  // -----------------------------------------------------------------------
  // validateType
  // -----------------------------------------------------------------------

  @Test
  public void testValidateType_correctType_isValid() {
    TestOptions opts = PipelineOptionsFactory.as(TestOptions.class);
    opts.setJobName("my-job");

    ValidationResult result =
        PipelineOptionsValidator.builder().validateType("jobName", String.class).validate(opts);

    assertTrue(result.isValid());
  }

  @Test
  public void testValidateType_nullValue_isValid() {
    // A null value passes type validation (use validateRequired for null checks).
    TestOptions opts = PipelineOptionsFactory.as(TestOptions.class);

    ValidationResult result =
        PipelineOptionsValidator.builder().validateType("jobName", String.class).validate(opts);

    assertTrue(result.isValid());
  }

  // -----------------------------------------------------------------------
  // validateRange
  // -----------------------------------------------------------------------

