 {@link Comparable}.\n     *\n     * @param fieldName the option property name\n     * @param min the minimum allowed value (inclusive)\n     * @param max the maximum allowed value (inclusive)\n     * @param <C> a {@link Comparable} type\n     * @return this builder\n     */\n    @SuppressWarnings({\"unchecked\", \"rawtypes\"})\n    public <C extends Comparable<C>> Builder validateRange(String fieldName, C min, C max) {\n      checkNotNull(fieldName, \"fieldName must not be null\");\n      checkNotNull(min, \"min must not be null\");\n      checkNotNull(max, \"max must not be null\");\n      checkArgument(\n          ((Comparable) min).compareTo(max) <= 0,", "numLines": 120, "startLine": 130, "totalLines": 332}}
